Function: import { InventoryItem } from './types';

export class Inventory {
  private items: InventoryItem[] = [];

  public addProduct(item: InventoryItem): void {
    this.items.push(item);
  }

  public getProduct(sku: string): InventoryItem | undefined {
    return this.items.find(item => item.sku === sku);
  }

  public listProducts(): InventoryItem[] {
    return this.items.slice();
  }

  public adjustQuantity(sku: string, quantity: number): InventoryItem {
    const item = this.items.find(item => item.sku === sku);
    if (!item) {
      throw new Error('product not found');
    }
    item.quantity += quantity;
    return item;
  }
}
